"""
Admin Blueprint — SSC Steno Portal
Routes:
  GET  /admin/login
  POST /admin/login
  GET  /admin/logout
  GET  /admin/dashboard          — overview stats + charts data
  GET  /admin/students           — all students table
  GET  /admin/student/<id>       — one student profile + all attempts
  GET  /admin/attempts           — all attempts table with filters
  GET  /admin/attempt/<id>       — detailed attempt + correction form
  POST /admin/attempt/<id>/correct — save manual correction
  GET  /admin/passages           — passages manager
  POST /admin/passages/add       — add new passage
  POST /admin/passages/toggle    — activate / deactivate
  POST /admin/students/add       — add new student
"""

import os, json
from functools import wraps
from flask import render_template_string, request, session, redirect, url_for, jsonify, flash, current_app

def render_template(name, **ctx):
    """Render admin template directly from embedded _TEMPLATES dict (no disk read)."""
    import base64 as _b64
    from flask import render_template_string
    b64 = _TEMPLATES.get(name)
    if not b64:
        raise Exception(f"Admin template not found: {name}")
    html = _b64.b64decode(b64).decode('utf-8')
    return render_template_string(html, **ctx)

# ── Embedded templates (auto-written to disk on first run) ──────────────────
_TEMPLATES = {
    "login.html": "",
    "base.html": "",
    "dashboard.html": "",
    "students.html": "",
    "student_profile.html": "",
    "attempt_detail.html": "",
    "attempts.html": "",
    "passages.html": "",
    "error.html": "",
    "student_monthly.html": "",
    "monthly_report.html": "",
    "evaluate.html": "",
}

def _ensure_templates():
    """Always overwrite disk templates from embedded data."""
    import base64 as _b64
    base = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'templates', 'admin')
    os.makedirs(base, exist_ok=True)
    for name, b64 in _TEMPLATES.items():
        path = os.path.join(base, name)
        html = _b64.b64decode(b64).decode('utf-8')
        with open(path, 'w', encoding='utf-8') as f:
            f.write(html)

_ensure_templates()

admin_bp = __import__('flask').Blueprint('admin', __name__, url_prefix='/admin')

ADMIN_PASSWORD = os.environ.get("ADMIN_PASSWORD", "admin@ssc2024")


# ── Auth guard ────────────────────────────────────────────────────────────────
def admin_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        if not session.get("admin_logged_in"):
            return redirect(url_for("admin.login"))
        return f(*args, **kwargs)
    return decorated


# ── Login / Logout ────────────────────────────────────────────────────────────
@admin_bp.route("/login", methods=["GET", "POST"])
def login():
    error = None
    if request.method == "POST":
        pw = request.form.get("password", "")
        if pw == ADMIN_PASSWORD:
            session["admin_logged_in"] = True
            return redirect(url_for("admin.dashboard"))
        error = "Incorrect password."
    return render_template("login.html", error=error)


@admin_bp.route("/logout")
def logout():
    session.pop("admin_logged_in", None)
    return redirect(url_for("admin.login"))


# ── Dashboard ─────────────────────────────────────────────────────────────────
@admin_bp.route("/dashboard")
@admin_required
def dashboard():
    from database.sheets_db import get_all_students, get_all_attempts, get_all_passages
    try:
        students = get_all_students()
        attempts = get_all_attempts()
        passages = get_all_passages()
    except Exception as e:
        return render_template("error.html", message=str(e))

    # ── Summary stats
    total_students = len(students)
    total_attempts = len(attempts)
    active_passages = sum(1 for p in passages if str(p.get("Active","")).lower() == "true")

    # Average error % across all attempts
    err_vals = []
    for a in attempts:
        try: err_vals.append(float(a.get("ErrorPercent", 0)))
        except: pass
    avg_error = round(sum(err_vals) / len(err_vals), 2) if err_vals else 0

    # Average WPM
    wpm_vals = []
    for a in attempts:
        try: wpm_vals.append(float(a.get("WPM", 0)))
        except: pass
    avg_wpm = round(sum(wpm_vals) / len(wpm_vals), 1) if wpm_vals else 0

    # Pass rate (ErrorPercent <= 5)
    passed = sum(1 for v in err_vals if v <= 5)
    pass_rate = round((passed / len(err_vals)) * 100, 1) if err_vals else 0

    # ── Chart: attempts per day (last 14 days)
    from collections import defaultdict
    day_counts = defaultdict(int)
    for a in attempts:
        date_str = str(a.get("Date", ""))[:10]
        if date_str:
            day_counts[date_str] += 1
    sorted_days = sorted(day_counts.items())[-14:]
    chart_days   = [d[0] for d in sorted_days]
    chart_counts = [d[1] for d in sorted_days]

    # ── Chart: error distribution across all attempts
    error_dist = {"full": 0, "half": 0, "omission": 0, "extra": 0, "cap": 0, "fullstop": 0}
    for a in attempts:
        try:
            error_dist["full"]     += float(a.get("FullMistakes", 0))
            error_dist["half"]     += float(a.get("HalfMistakes", 0))
            error_dist["omission"] += float(a.get("Omissions", 0))
            error_dist["extra"]    += float(a.get("ExtraWords", 0))
            error_dist["cap"]      += float(a.get("Capitalization", 0))
            error_dist["fullstop"] += float(a.get("FullStop", 0))
        except: pass

    # ── Top 5 students by avg error (lowest = best)
    from collections import defaultdict
    student_errors = defaultdict(list)
    student_wpm    = defaultdict(list)
    for a in attempts:
        sid = str(a.get("StudentID",""))
        try: student_errors[sid].append(float(a.get("ErrorPercent", 0)))
        except: pass
        try: student_wpm[sid].append(float(a.get("WPM", 0)))
        except: pass

    student_map = {str(s.get("StudentID","")): s.get("StudentName", s.get("Name","")) for s in students}

    leaderboard = []
    for sid, errs in student_errors.items():
        avg_e = round(sum(errs)/len(errs), 2)
        avg_w = round(sum(student_wpm[sid])/len(student_wpm[sid]), 1) if student_wpm[sid] else 0
        leaderboard.append({
            "id": sid,
            "name": student_map.get(sid, sid),
            "attempts": len(errs),
            "avg_error": avg_e,
            "avg_wpm": avg_w,
            "best_error": round(min(errs), 2),
        })
    leaderboard.sort(key=lambda x: (x["avg_error"], -x["avg_wpm"]))

    # ── Recent 10 attempts
    recent = sorted(attempts, key=lambda a: str(a.get("Date","")), reverse=True)[:10]
    for r in recent:
        r["_name"] = student_map.get(str(r.get("StudentID","")), r.get("StudentID",""))

    return render_template("dashboard.html",
        total_students=total_students,
        total_attempts=total_attempts,
        active_passages=active_passages,
        avg_error=avg_error,
        avg_wpm=avg_wpm,
        pass_rate=pass_rate,
        chart_days=json.dumps(chart_days),
        chart_counts=json.dumps(chart_counts),
        error_dist=json.dumps(error_dist),
        leaderboard=leaderboard[:10],
        recent=recent,
    )


# ── Students list ─────────────────────────────────────────────────────────────
@admin_bp.route("/students")
@admin_required
def students():
    from database.sheets_db import get_all_students, get_all_attempts
    all_students = get_all_students()
    all_attempts = get_all_attempts()

    from collections import defaultdict
    student_attempts = defaultdict(list)
    for a in all_attempts:
        student_attempts[str(a.get("StudentID",""))].append(a)

    rows = []
    for s in all_students:
        sid = str(s.get("StudentID",""))
        atts = student_attempts[sid]
        err_vals = []
        wpm_vals = []
        for a in atts:
            try: err_vals.append(float(a.get("ErrorPercent",0)))
            except: pass
            try: wpm_vals.append(float(a.get("WPM",0)))
            except: pass
        rows.append({
            "id":         sid,
            "name":       s.get("StudentName", s.get("Name","")),
            "batch":      s.get("Batch",""),
            "attempts":   len(atts),
            "avg_error":  round(sum(err_vals)/len(err_vals),2) if err_vals else "-",
            "avg_wpm":    round(sum(wpm_vals)/len(wpm_vals),1) if wpm_vals else "-",
            "best_error": round(min(err_vals),2) if err_vals else "-",
            "last_date":  max((str(a.get("Date","")) for a in atts), default="-"),
        })
    rows.sort(key=lambda x: x["name"])
    return render_template("students.html", rows=rows)


# ── Student profile ───────────────────────────────────────────────────────────
@admin_bp.route("/student/<student_id>")
@admin_required
def student_profile(student_id):
    from database.sheets_db import get_student, get_attempts_by_student
    student  = get_student(student_id)
    attempts = get_attempts_by_student(student_id)
    attempts.sort(key=lambda a: str(a.get("Date","")), reverse=True)

    # Progress data for chart: date + error%
    progress = [(str(a.get("Date",""))[:10], float(a.get("ErrorPercent",0)),
                 float(a.get("WPM",0))) for a in attempts
                if a.get("Date")]
    progress.sort(key=lambda x: x[0])

    return render_template("student_profile.html",
        student=student,
        attempts=attempts,
        progress_dates=json.dumps([p[0] for p in progress]),
        progress_errors=json.dumps([p[1] for p in progress]),
        progress_wpm=json.dumps([p[2] for p in progress]),
    )


# ── All attempts ──────────────────────────────────────────────────────────────
@admin_bp.route("/attempts")
@admin_required
def attempts_list():
    from database.sheets_db import get_all_attempts, get_all_students
    attempts = get_all_attempts()
    students = get_all_students()
    student_map = {str(s.get("StudentID","")): s.get("StudentName", s.get("Name",""))
                   for s in students}
    for a in attempts:
        a["_name"] = student_map.get(str(a.get("StudentID","")), a.get("StudentID",""))
    attempts.sort(key=lambda a: str(a.get("Date","")), reverse=True)

    # Filter params
    sid    = request.args.get("student", "")
    code   = request.args.get("passage", "")
    date   = request.args.get("date", "")
    if sid:   attempts = [a for a in attempts if str(a.get("StudentID","")) == sid]
    if code:  attempts = [a for a in attempts if str(a.get("PassageCode","")).lower() == code.lower()]
    if date:  attempts = [a for a in attempts if str(a.get("Date","")).startswith(date)]

    return render_template("attempts.html",
        attempts=attempts, student_map=student_map,
        filter_sid=sid, filter_code=code, filter_date=date)


