@admin_bp.route("/attempt/<attempt_id>/correct", methods=["POST"])
@admin_required
def correct_attempt(attempt_id):
    from database.sheets_db import get_attempt_by_id, update_attempt_errors
    data = request.get_json()

    try:
        full  = float(data.get("full", 0))
        half  = float(data.get("half", 0))
        omit  = float(data.get("omission", 0))
        extra = float(data.get("extra", 0))
        cap   = float(data.get("capitalization", 0))
        fs    = float(data.get("fullstop", 0))
        note  = str(data.get("note", "")).strip()

        total = full + half + omit + extra + cap + fs

        # Get word count from attempt (TypedWords) — don't require active passage
        attempt = get_attempt_by_id(attempt_id)
        if not attempt:
            return jsonify({"status": "error", "message": "Attempt not found."})

        # Try passage first, fall back to TypedWords
        word_base = 0
        # Try passage word count first (most accurate)
        try:
            from database.sheets_db import get_passage_any
            p = get_passage_any(str(attempt.get("PassageCode", "")))
            word_base = int(p["word_count"]) if p else 0
        except Exception:
            pass
        # Fall back to TypedWords or WordCount from attempt record
        if not word_base:
            for key in ("TotalWords", "WordCount", "TypedWords"):
                try:
                    v = int(attempt.get(key, 0) or 0)
                    if v > 0:
                        word_base = v
                        break
                except Exception:
                    pass
        if not word_base:
            word_base = 100  # last resort

        err_pct = round((total / word_base) * 100, 2)

        corrected = {
            "FullMistakes":   full,
            "HalfMistakes":   half,
            "Omissions":      omit,
            "ExtraWords":     extra,
            "Capitalization": cap,
            "FullStop":       fs,
            "TotalErrors":    total,
            "ErrorPercent":   err_pct,
        }
        if note:
            corrected["AdminNote"] = note

        ok = update_attempt_errors(attempt_id, corrected)
        if ok:
            return jsonify({"status": "ok", "new_total": total, "new_pct": err_pct})
        return jsonify({"status": "error", "message": "Row not found in sheet."})
    except Exception as e:
        import traceback
        traceback.print_exc()
        return jsonify({"status": "error", "message": str(e)}), 500


# ── Passages manager ──────────────────────────────────────────────────────────
@admin_bp.route("/passages")
@admin_required
def passages():
    from database.sheets_db import get_all_passages, get_all_attempts
    all_passages = get_all_passages()
    all_attempts = get_all_attempts()

    from collections import defaultdict
    passage_attempts = defaultdict(int)
    for a in all_attempts:
        passage_attempts[str(a.get("PassageCode","")).lower()] += 1

    # Build safe passage list — strip full text, normalise field names
    safe_passages = []
    for p in all_passages:
        code = str(p.get("PassageCode", p.get("Code", ""))).strip()
        # Try multiple possible column names for passage name
        name = str(p.get("PassageName",
                   p.get("Name",
                   p.get("Title",
                   p.get("passage_name", code))))).strip()
        words = str(p.get("TotalWords",
                    p.get("WordCount",
                    p.get("Words", "")))).strip()
        active = str(p.get("Active", "false")).strip()
        safe_passages.append({
            "PassageCode":   code,
            "PassageName":   name,
            "TotalWords":    words,
            "Active":        active,
            "_attempt_count": passage_attempts[code.lower()],
        })

    return render_template("passages.html", passages=safe_passages)


@admin_bp.route("/passages/toggle", methods=["POST"])
