@admin_bp.route("/passages/add", methods=["POST"])
@admin_required
def add_passage():
    from database.sheets_db import add_passage as db_add
    data = request.get_json()
    code  = str(data.get("code","")).strip()
    name  = str(data.get("name","")).strip()
    text  = str(data.get("text","")).strip()
    words = len(text.split())
    if not code or not name or not text:
        return jsonify({"status": "error", "message": "All fields required."})
    category = str(data.get("category","")).strip()
    speed    = str(data.get("speed","")).strip()
    try:
        db_add(code, name, text, words, active=True, category=category, speed=speed)
        return jsonify({"status": "ok", "word_count": words})
    except Exception as e:
        return jsonify({"status": "error", "message": str(e)})


