# ── Simulation endpoint ───────────────────────────────────────────────────────
@admin_bp.route("/simulate-eval", methods=["POST"])
@admin_required
def simulate_eval():
    """Re-run evaluation engine on pasted typed text for a given attempt."""
    from database.sheets_db import get_attempt_by_id, get_passage
    from engine.evaluation_engine import evaluate, highlight_passage

    data       = request.get_json()
    typed_text = str(data.get("typed_text", "")).strip()
    attempt_id = str(data.get("attempt_id", "")).strip()

    if not typed_text or not attempt_id:
        return jsonify({"status": "error", "message": "Missing typed_text or attempt_id"})

    try:
        attempt = get_attempt_by_id(attempt_id)
        if not attempt:
            return jsonify({"status": "error", "message": "Attempt not found"})

        passage = get_passage(str(attempt.get("PassageCode", "")))
        if not passage:
            return jsonify({"status": "error", "message": "Passage not found"})

        result = evaluate(passage["text"], typed_text, passage["word_count"])
        highlighted = highlight_passage(passage["text"], typed_text)

        return jsonify({
            "status":     "ok",
            "full":       result["full"],
            "half":       result["half"],
            "omission":   result["omission"],
            "extra":      result["extra"],
            "cap":        result["capitalization"],
            "fullstop":   result["fullstop"],
            "total":      result["total_errors"],
            "error_pct":  result["error_percent"],
            "highlighted": highlighted,
        })
    except Exception as e:
        import traceback
        traceback.print_exc()
        return jsonify({"status": "error", "message": str(e)})

