@admin_bp.route("/quick-eval", methods=["POST"])
@admin_required
def quick_eval():
    from database.sheets_db import get_passage
    from engine.evaluation_engine import evaluate, highlight_passage
    data         = request.get_json()
    passage_code = str(data.get("passage_code", "")).strip()
    typed_text   = str(data.get("typed_text", "")).strip()
    if not passage_code or not typed_text:
        return jsonify({"status": "error", "message": "Missing fields"})
    try:
        passage = get_passage(passage_code)
        if not passage:
            return jsonify({"status": "error", "message": "Passage not found"})
        result      = evaluate(passage["text"], typed_text, passage["word_count"])
        highlighted = highlight_passage(passage["text"], typed_text)
        typed_words = len(typed_text.split())
        wpm = round(typed_words / (passage["word_count"] / 80))  # approx 80wpm pace
        return jsonify({
            "status": "ok",
            "full": result["full"], "half": result["half"],
            "omission": result["omission"], "extra": result["extra"],
            "cap": result["capitalization"], "fullstop": result["fullstop"],
            "total": result["total_errors"], "error_pct": result["error_percent"],
            "wpm": wpm, "highlighted": highlighted,
        })
    except Exception as e:
        import traceback; traceback.print_exc()
        return jsonify({"status": "error", "message": str(e)})


@admin_bp.route("/quick-eval/save", methods=["POST"])
@admin_required
def quick_eval_save():
    from database.sheets_db import get_passage, save_attempt, build_attempt_record
    from engine.evaluation_engine import evaluate, highlight_passage
    data         = request.get_json()
    passage_code = str(data.get("passage_code", "")).strip()
    typed_text   = str(data.get("typed_text", "")).strip()
    student_id   = str(data.get("student_id", "")).strip()
    time_taken   = int(data.get("time_taken", 0))
    if not passage_code or not typed_text or not student_id:
        return jsonify({"status": "error", "message": "Missing fields"})
    try:
        passage     = get_passage(passage_code)
        result      = evaluate(passage["text"], typed_text, passage["word_count"])
        highlighted = highlight_passage(passage["text"], typed_text)
        typed_words = len(typed_text.split())
        minutes     = time_taken / 60 if time_taken > 0 else 1
        result["wpm"] = round(typed_words / minutes)
        record = build_attempt_record(student_id, passage_code, result,
                                      time_taken, typed_words, highlighted)
        save_attempt(record)
        return jsonify({"status": "ok", "attempt_id": record["AttemptID"]})
    except Exception as e:
        import traceback; traceback.print_exc()
        return jsonify({"status": "error", "message": str(e)})



# ── Student-wise Monthly Report ───────────────────────────────────────────────
@admin_bp.route("/report/student/<student_id>")
@admin_required
def student_monthly_report(student_id):
    from database.sheets_db import get_student, get_attempts_by_student
    import calendar
    from datetime import datetime

    student  = get_student(student_id)
    attempts = get_attempts_by_student(student_id)

    now   = datetime.now()
    year  = int(request.args.get('year',  now.year))
    month = int(request.args.get('month', now.month))
    month_name = calendar.month_name[month]

    # Filter by month
    def in_month(a):
        return str(a.get('Date',''))[:7] == f'{year:04d}-{month:02d}'

    month_attempts = [a for a in attempts if in_month(a)]
    all_attempts   = sorted(attempts, key=lambda a: str(a.get('Date','')), reverse=True)

    # Monthly stats
    err_vals = []
    wpm_vals = []
    for a in month_attempts:
        try: err_vals.append(float(a.get('ErrorPercent',0)))
        except: pass
        try: wpm_vals.append(float(a.get('WPM',0)))
        except: pass

    summary = {
        'attempts':  len(month_attempts),
        'avg_err':   round(sum(err_vals)/len(err_vals),2) if err_vals else 0,
        'best_err':  round(min(err_vals),2)               if err_vals else 0,
        'worst_err': round(max(err_vals),2)               if err_vals else 0,
        'avg_wpm':   round(sum(wpm_vals)/len(wpm_vals),1) if wpm_vals else 0,
        'passed':    sum(1 for e in err_vals if e<=5),
        'pass_rate': round(sum(1 for e in err_vals if e<=5)/len(err_vals)*100,1) if err_vals else 0,
    }

    # Available years/months from all attempts
    years  = sorted(set(str(a.get('Date',''))[:4] for a in attempts if a.get('Date')), reverse=True)
    months = list(range(1,13))

    return render_template('student_monthly.html',
        student=student, student_id=student_id,
        month_name=month_name, month=month, year=year,
        summary=summary,
        month_attempts=sorted(month_attempts, key=lambda a: str(a.get('Date','')), reverse=True),
        years=years, months=months,
        calendar=calendar,
    )


# ── Monthly Report ────────────────────────────────────────────────────────────
@admin_bp.route("/report/monthly")
@admin_required
def monthly_report():
    from database.sheets_db import get_all_attempts, get_all_students, get_all_passages
    import calendar
    from collections import defaultdict

    attempts  = get_all_attempts()
    students  = get_all_students()
    passages  = get_all_passages()

    # Get requested month/year (default = current)
    now   = __import__('datetime').datetime.now()
    year  = int(request.args.get('year',  now.year))
    month = int(request.args.get('month', now.month))

    month_name = calendar.month_name[month]

    # Filter attempts for this month
    def in_month(a):
        d = str(a.get('Date',''))[:7]  # "YYYY-MM"
        return d == f'{year:04d}-{month:02d}'

    month_attempts = [a for a in attempts if in_month(a)]

    student_map = {str(s.get('StudentID','')): s.get('StudentName', s.get('Name',''))
                   for s in students}

    # ── Per-student stats
    stu_stats = defaultdict(lambda: {
        'name':'', 'attempts':0, 'total_err':0, 'total_wpm':0,
        'full':0,'half':0,'omission':0,'extra':0,'cap':0,'fullstop':0,
        'best_err': None, 'passages': set()
    })
    for a in month_attempts:
        sid = str(a.get('StudentID',''))
        s = stu_stats[sid]
        s['name'] = student_map.get(sid, sid)
        s['attempts'] += 1
        try: s['total_err'] += float(a.get('ErrorPercent',0))
        except: pass
        try: s['total_wpm'] += float(a.get('WPM',0))
        except: pass
        try:
            e = float(a.get('ErrorPercent',0))
            s['best_err'] = e if s['best_err'] is None else min(s['best_err'], e)
        except: pass
        for k in ('FullMistakes','HalfMistakes','Omissions','ExtraWords','Capitalization','FullStop'):
            try: s[k.lower().replace('mistakes','').replace('words','').replace('ization','').replace('stop','stop')] 
            except: pass
        s['passages'].add(str(a.get('PassageCode','')))

    rows = []
    for sid, s in stu_stats.items():
        n = s['attempts'] or 1
        rows.append({
            'id':       sid,
            'name':     s['name'],
            'attempts': s['attempts'],
            'avg_err':  round(s['total_err']/n, 2),
            'avg_wpm':  round(s['total_wpm']/n, 1),
            'best_err': round(s['best_err'], 2) if s['best_err'] is not None else '-',
            'passages': len(s['passages']),
        })
    rows.sort(key=lambda x: x['avg_err'])

    # ── Overall summary
    all_errs = []
    all_wpms = []
    for a in month_attempts:
        try: all_errs.append(float(a.get('ErrorPercent',0)))
        except: pass
        try: all_wpms.append(float(a.get('WPM',0)))
        except: pass

    passed  = sum(1 for e in all_errs if e <= 5)
    summary = {
        'total_attempts': len(month_attempts),
        'total_students': len(stu_stats),
        'avg_err':   round(sum(all_errs)/len(all_errs),2) if all_errs else 0,
        'avg_wpm':   round(sum(all_wpms)/len(all_wpms),1) if all_wpms else 0,
        'pass_rate': round(passed/len(all_errs)*100,1)    if all_errs else 0,
        'best_err':  round(min(all_errs),2)               if all_errs else 0,
    }

    # ── Passage usage
    p_counts = defaultdict(int)
    p_errs   = defaultdict(list)
    for a in month_attempts:
        code = str(a.get('PassageCode',''))
        p_counts[code] += 1
        try: p_errs[code].append(float(a.get('ErrorPercent',0)))
        except: pass
    passage_name_map = {str(p.get('PassageCode','')): str(p.get('PassageName','')) for p in passages}
    passage_rows = sorted([{
        'code': code,
        'name': passage_name_map.get(code, code),
        'count': cnt,
        'avg_err': round(sum(p_errs[code])/len(p_errs[code]),2) if p_errs[code] else 0,
    } for code, cnt in p_counts.items()], key=lambda x: -x['count'])

    # Build year/month options for selector
    years  = sorted(set(str(a.get('Date',''))[:4] for a in attempts if a.get('Date')), reverse=True)
    months = list(range(1,13))

    return render_template('monthly_report.html',
        year=year, month=month, month_name=month_name,
        summary=summary, rows=rows,
        passage_rows=passage_rows,
        years=years, months=months,
        calendar=calendar,
    )


# ── Manual annotation save ────────────────────────────────────────────────────
@admin_bp.route("/attempt/<attempt_id>/annotate", methods=["POST"])
@admin_required
def annotate_attempt(attempt_id):
    """Save manually corrected annotation + recalculated scores."""
    from database.sheets_db import get_attempt_row_index, update_attempt_errors
    data = request.get_json()
    if not data:
        return jsonify({"status": "error", "message": "No data"})
    try:
        row = get_attempt_row_index(attempt_id)
        if not row:
            return jsonify({"status": "error", "message": "Attempt not found"})

        full      = float(data.get("full", 0))
        half      = float(data.get("half", 0))
        omission  = float(data.get("omission", 0))
        extra     = float(data.get("extra", 0))
        cap       = float(data.get("capitalization", 0))
        fs        = float(data.get("fullstop", 0))
        total     = full + half + omission + extra + cap + fs
        note      = str(data.get("note", "Manual annotation edit"))
        highlighted = str(data.get("highlighted_html", ""))

        # Get word count to compute error %
        from database.sheets_db import get_attempt_by_id
        attempt = get_attempt_by_id(attempt_id)
        wc = int(attempt.get("WordCount", 100) or 100)
        error_pct = round((total / wc) * 100, 2) if wc > 0 else 0

        corrected = {
            "FullMistakes":   full,
            "HalfMistakes":   half,
            "Omissions":      omission,
            "ExtraWords":     extra,
            "Capitalization": cap,
            "FullStop":       fs,
            "TotalErrors":    total,
            "ErrorPercent":   error_pct,
            "AdminNote":      note,
        }
        update_attempt_errors(attempt_id, corrected)

        # Also update HighlightedPassage if provided
        if highlighted:
            from database.sheets_db import update_highlighted_passage
            try:
                update_highlighted_passage(attempt_id, highlighted)
            except Exception:
                pass  # non-critical

        return jsonify({"status": "ok", "error_pct": error_pct})
    except Exception as e:
        import traceback; traceback.print_exc()
        return jsonify({"status": "error", "message": str(e)})
